use std::mem;

#[repr(C)]
struct Point {
    x: f32,
    y: f32,
}

extern "C" fn calculate_monte_carlo(start_points: *const Point, num_points: usize, steps: usize) -> f32 {
    let start_slice = unsafe { std::slice::from_raw_parts(start_points, num_points) };
    if start_slice.is_empty() || steps == 0 {
        return 0.0;
    }

    let mut sum: f32 = 0.0;

    for _ in 0..steps {
        let mut current_sum: f32 = 0.0;
        for point in start_slice.iter() {
            let mut x: f32 = point.x;
            let mut y: f32 = point.y;

            for _step in 0..steps {
                x += (rand::random::<f32>() - 0.5) * 1.0;
                y += (rand::random::<f32>() - 0.5) * 1.0;
            }
            current_sum += x * y;
        }
        sum += current_sum / start_slice.len() as f32;
    }

    sum / steps as f32
}
